from fastapi import FastAPI

app = FastAPI(
    title="My Custom FastAPI Application",
    description="This is a very fancy API that allows you to do awesome things. "
                "It has custom OpenAPI documentation settings.",
    version="2.0.0",
    terms_of_service="http://example.com/terms/",
    contact={
        "name": "Developer Team",
        "url": "http://x-force.example.com/contact/",
        "email": "dev@example.com",
    },
    license_info={
        "name": "Apache 2.0",
        "url": "https://www.apache.org/licenses/LICENSE-2.0.html",
    },
    openapi_tags=[
        {
            "name": "items",
            "description": "Operations with items. Manage your items here.",
        },
        {
            "name": "users",
            "description": "Operations with users. Register, login, manage profiles.",
            "externalDocs": {
                "description": "Users external docs",
                "url": "https://example.com/users-docs",
            },
        },
    ],
)


@app.get("/")
async def read_root():
    return {"message": "Hello World"}


@app.get("/items/{item_id}", tags=["items"])
async def read_item(item_id: int):
    return {"item_id": item_id, "name": f"Item {item_id}"}


@app.get("/users/{user_id}", tags=["users"])
async def read_user(user_id: int):
    return {"user_id": user_id, "username": f"user_{user_id}"}
